#include <concepts>
#include <iostream>
#include <string>

template<typename T>
concept Printable = requires(T x) {
    { x.to_string() } -> std::convertible_to<std::string>;
};

struct Point {
    int x, y;
    std::string to_string() const {
        return "(" + std::to_string(x) + ", " + std::to_string(y) + ")";
    }
};

struct Opaque { int data; }; // no to_string()

template<Printable T>
void print_item(const T& item) {
    std::cout << "item: " << item.to_string() << "\n";
}

int main() {
    print_item(Point{3, 4});
    // print_item(Opaque{42}); // would not compile

    std::cout << "Point satisfies Printable: " << std::boolalpha << Printable<Point> << "\n";
    std::cout << "Opaque satisfies Printable: " << Printable<Opaque> << "\n";
}

#include <concepts>
#include <iostream>

template<std::integral T>
T double_it(T x) { return x * 2; }

template<std::floating_point T>
T double_it(T x) { return x * 2.0; }

template<std::totally_ordered T>
T clamp(T val, T lo, T hi) {
    if (val < lo) return lo;
    if (val > hi) return hi;
    return val;
}

int main() {
    std::cout << "double_it(5): " << double_it(5) << "\n";
    std::cout << "double_it(2.5): " << double_it(2.5) << "\n";
    std::cout << "clamp(15, 0, 10): " << clamp(15, 0, 10) << "\n";
    std::cout << "clamp(-3, 0, 10): " << clamp(-3, 0, 10) << "\n";

    std::cout << std::boolalpha;
    std::cout << "int is integral: " << std::integral<int> << "\n";
    std::cout << "double is integral: " << std::integral<double> << "\n";
    std::cout << "int is regular: " << std::regular<int> << "\n";
}

#include <concepts>
#include <cstddef>
#include <iostream>
#include <string>
#include <vector>

template<typename T>
concept Container = requires(T c, const T cc) {
    // Simple: operation must be valid
    c.begin();
    c.end();
    // Compound: must return convertible type
    { cc.size() } -> std::convertible_to<std::size_t>;
    { cc.empty() } -> std::same_as<bool>;
    // Type requirement: nested type must exist
    typename T::value_type;
    // Nested: another concept must be satisfied
    requires std::copyable<typename T::value_type>;
};

template<Container C>
void describe(const C& c) {
    std::cout << "size: " << c.size() << ", empty: " << std::boolalpha << c.empty() << "\n";
}

int main() {
    std::vector<int> v = {1, 2, 3};
    describe(v);

    std::cout << std::boolalpha;
    std::cout << "vector<int> is Container: " << Container<std::vector<int>> << "\n";
    std::cout << "int is Container: " << Container<int> << "\n";
    std::cout << "string is Container: " << Container<std::string> << "\n";
}

#include <concepts>
#include <iostream>
#include <string>

// Синтаксис 1: концепт как параметр типа
template<std::integral T>
T square1(T x) { return x * x; }

// Синтаксис 2: abbreviated (каждый auto — отдельный тип)
auto add(std::integral auto a, std::integral auto b) {
    return a + b;
}

// Синтаксис 3: trailing requires
template<typename T>
T square3(T x) requires std::integral<T> { return x * x; }

// Синтаксис 4: requires в заголовке шаблона
template<typename T> requires std::integral<T>
T square4(T x) { return x * x; }

int main() {
    std::cout << "square1(5): " << square1(5) << '\n';
    std::cout << "add(3, 4L): " << add(3, 4L) << '\n';  // int и long — OK, разные типы
    std::cout << "square3(7): " << square3(7) << '\n';
    std::cout << "square4(9): " << square4(9) << '\n';
}

#include <concepts>
#include <vector>
#include <algorithm>
#include <iostream>

template<typename T>
class SortedBuffer {
    std::vector<T> data_;
public:
    void insert(T val) {
        data_.push_back(std::move(val));
        std::sort(data_.begin(), data_.end());
    }

    // Метод существует только когда T поддерживает сравнение
    const T& min() const requires std::totally_ordered<T> {
        return data_.front();
    }

    const T& max() const requires std::totally_ordered<T> {
        return data_.back();
    }

    std::size_t size() const { return data_.size(); }
};

// NTTP с концептом
template<std::size_t N> requires (N > 0)
struct RingSize {
    static constexpr std::size_t value = N;
};

int main() {
    SortedBuffer<int> buf;
    buf.insert(5);
    buf.insert(2);
    buf.insert(8);
    buf.insert(1);

    std::cout << "size: " << buf.size() << '\n';
    std::cout << "min: " << buf.min() << '\n';
    std::cout << "max: " << buf.max() << '\n';

    std::cout << "RingSize<4>::value: " << RingSize<4>::value << '\n';
}

#include <concepts>
#include <iostream>
#include <string>

// Менее ограничен: любой интегральный тип
template<std::integral T>
std::string classify(T) { return "integral"; }

// Более ограничен: знаковый интегральный (subsumes integral)
template<std::signed_integral T>
std::string classify(T) { return "signed integral"; }

// Ещё более ограничен: знаковый И sizeof > 1
template<typename T>
    requires std::signed_integral<T> && (sizeof(T) > 1)
std::string classify(T) { return "signed integral (multi-byte)"; }

int main() {
    std::cout << "classify(42):             " << classify(42) << '\n';          // int: знаковый и sizeof=4
    std::cout << "classify(42u):            " << classify(42u) << '\n';         // unsigned: только integral
    std::cout << "classify((short)1):       " << classify((short)1) << '\n';   // short: знаковый, sizeof=2
    std::cout << "classify((signed char)1): " << classify((signed char)1) << '\n'; // sizeof=1 — не multi-byte
}

#include <concepts>
#include <iostream>

// Конъюнкция: интегральный И sizeof >= 4
template<typename T>
concept WideIntegral = std::integral<T> && (sizeof(T) >= 4);

// Дизъюнкция: числоподобный (int или float)
template<typename T>
concept Numeric = std::integral<T> || std::floating_point<T>;

template<WideIntegral T>
void store(T x) {
    std::cout << "wide integral store: " << x << " (" << sizeof(T) << " bytes)\n";
}

template<Numeric T> requires (!WideIntegral<T>)
void store(T x) {
    std::cout << "other numeric store: " << x << '\n';
}

int main() {
    store(42);       // int: WideIntegral (sizeof==4)
    store(42LL);     // long long: WideIntegral (sizeof==8)
    store(3.14);     // double: Numeric, но не WideIntegral
    store((short)1); // short: Numeric, но не WideIntegral (sizeof==2)
    store(2.718f);   // float: Numeric, но не WideIntegral

    std::cout << std::boolalpha;
    std::cout << "WideIntegral<int>:    " << WideIntegral<int> << '\n';
    std::cout << "WideIntegral<short>:  " << WideIntegral<short> << '\n';
    std::cout << "Numeric<double>:      " << Numeric<double> << '\n';
    std::cout << "Numeric<std::string>: " << Numeric<std::string> << '\n';
}

#include <concepts>
#include <ranges>
#include <iostream>
#include <vector>
#include <list>
#include <string>
#include <functional>

template<typename T>
concept Hashable = requires(T a) {
    { std::hash<T>{}(a) } -> std::convertible_to<std::size_t>;
    { a == a } -> std::convertible_to<bool>;
};

template<Hashable T>
bool try_hash(const T& val) {
    std::size_t h = std::hash<T>{}(val);
    return h >= 0; // size_t беззнаковый — всегда true
}

template<std::ranges::input_range R>
void print_range(const R& r) {
    for (const auto& x : r)
        std::cout << x << ' ';
    std::cout << '\n';
}

int main() {
    std::cout << std::boolalpha;
    std::cout << "Hashable<int>:         " << Hashable<int> << '\n';
    std::cout << "Hashable<std::string>: " << Hashable<std::string> << '\n';
    std::cout << "hash computed:         " << try_hash(42) << '\n';

    std::vector<int> v = {1, 2, 3, 4, 5};
    std::list<int> l = {6, 7, 8};

    std::cout << "vector: "; print_range(v);
    std::cout << "list:   "; print_range(l);

    std::cout << "vector is contiguous_range:   " << std::ranges::contiguous_range<decltype(v)> << '\n';
    std::cout << "list is contiguous_range:     " << std::ranges::contiguous_range<decltype(l)> << '\n';
    std::cout << "list is bidirectional_range:  " << std::ranges::bidirectional_range<decltype(l)> << '\n';
}

#include <concepts>
#include <ranges>
#include <algorithm>
#include <iostream>
#include <vector>
#include <list>

// Достаточно input_range — работает на любом контейнере
template<std::ranges::input_range R>
typename std::ranges::range_value_t<R>
range_sum(const R& r) {
    typename std::ranges::range_value_t<R> sum{};
    for (const auto& x : r) sum += x;
    return sum;
}

// Бинарный поиск требует random_access_range
template<std::ranges::random_access_range R>
bool binary_contains(const R& r, const std::ranges::range_value_t<R>& val) {
    return std::binary_search(std::ranges::begin(r), std::ranges::end(r), val);
}

int main() {
    std::cout << std::boolalpha;

    std::vector<int> v = {1, 2, 3, 4, 5};
    std::list<int> l = {10, 20, 30};

    std::cout << "sum(vector): " << range_sum(v) << '\n';
    std::cout << "sum(list):   " << range_sum(l) << '\n';

    // binary_contains работает только на random_access:
    std::cout << "vector has 3: " << binary_contains(v, 3) << '\n';
    std::cout << "vector has 7: " << binary_contains(v, 7) << '\n';
    // binary_contains(l, 10) — не скомпилируется: list не random_access

    // Проверка концептов
    std::cout << "vector is random_access_range: " << std::ranges::random_access_range<decltype(v)> << '\n';
    std::cout << "list is random_access_range:   " << std::ranges::random_access_range<decltype(l)> << '\n';
    std::cout << "list is bidirectional_range:   " << std::ranges::bidirectional_range<decltype(l)> << '\n';
}
